#include <stdio.h>
int main(void) {
    unsigned int a = 0xA5;
    unsigned int b = 0x0F;
    printf("a        = 0x%02X\n", a);
    printf("b        = 0x%02X\n", b);
    printf("a AND b  = 0x%02X\n", a & b);
    printf("a OR  b  = 0x%02X\n", a | b);
    printf("a XOR b  = 0x%02X\n", a ^ b);
    printf("NOT a    = 0x%02X\n", (~a) & 0xFF);
    printf("a << 2   = 0x%02X\n", (a << 2) & 0xFF);
    printf("a >> 2   = 0x%02X\n", a >> 2);
    return 0;
}

