#include <stdio.h>

/* == EXEMPLE ================================================
 * Operations bit-a-bit sur 0xCC et 0x33
 * Memes operateurs : AND(&), OR(|), XOR(^), NOT(~), shifts
 * =========================================================== */
void example_bitwise(void) {
    unsigned int x = 0xCC; /* 11001100b */
    unsigned int y = 0x33; /* 00110011b */
    printf("x        = 0x%02X\n", x);
    printf("y        = 0x%02X\n", y);
    printf("x AND y  = 0x%02X\n", x & y);        /* 0x00 */
    printf("x OR  y  = 0x%02X\n", x | y);        /* 0xFF */
    printf("x XOR y  = 0x%02X\n", x ^ y);        /* 0xFF */
    printf("NOT x    = 0x%02X\n", (~x) & 0xFF);  /* 0x33 */
    printf("x << 1   = 0x%02X\n", (x << 1) & 0xFF); /* 0x98 */
    printf("x >> 1   = 0x%02X\n", x >> 1);       /* 0x66 */
}
